import { FC, ReactElement, useCallback, useMemo, useState } from 'react';

import { I18nNamespace } from '@config/config';
import ExternalLink from '@core/components/ExternalLink';
import DeploymentNetworkConsoleButton from '@pages/components/DeploymentNetworkConsoleButton';
import {
  Button,
  ButtonVariant,
  Content,
  DataList,
  DataListAction,
  DataListCell,
  DataListItem,
  DataListItemCells,
  DataListItemRow,
  Flex,
  FlexItem,
  Modal,
  ModalVariant,
  PageSection
} from '@patternfly/react-core';
import { useTranslation } from 'react-i18next';

import ConnectorForm from '../components/forms/ConnectorForm';
import GrantForm from '../components/forms/GrantForm';
import LinkForm from '../components/forms/LinkForm';
import ListenerForm from '../components/forms/ListenerForm';

enum Actions {
  Token = 'token',
  Link = 'link',
  Listener = 'listener',
  Connector = 'connector'
}

const GetStarted: FC<{ siteId: string }> = function ({ siteId }) {
  const { t } = useTranslation(I18nNamespace);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [action, setAction] = useState('');

  const handleModalClose = useCallback(() => {
    setIsModalOpen(false);
  }, []);

  const handleOperation = (newAction: string) => {
    setAction(newAction);
    setIsModalOpen(true);
  };

  const ActionFormMap: Record<string, ReactElement> = useMemo(
    () => ({
      [Actions.Token]: <GrantForm onSubmit={handleModalClose} onCancel={handleModalClose} />,
      [Actions.Link]: <LinkForm onSubmit={handleModalClose} onCancel={handleModalClose} siteId={siteId} />,
      [Actions.Listener]: (
        <ListenerForm onSubmit={handleModalClose} onCancel={handleModalClose} title={t('Create a listener')} />
      ),
      [Actions.Connector]: (
        <ConnectorForm onSubmit={handleModalClose} onCancel={handleModalClose} title={t('Create a Connector')} />
      )
    }),
    [handleModalClose, siteId, t]
  );

  const DetailItem: FC<{
    title: string;
    description: string;
    btnName?: string;
    actionName?: string;
    onClick: (action: string) => void;
  }> = function ({ title, description, actionName, btnName, onClick }) {
    return (
      <DataListItem>
        <DataListItemRow>
          <DataListItemCells
            dataListCells={[
              <DataListCell key={`key=${actionName}`}>
                <Flex spaceItems={{ default: 'spaceItemsMd' }} direction={{ default: 'column' }}>
                  <FlexItem>
                    <Content component="h1">{title}</Content>
                    <Content component="p">{description}</Content>
                  </FlexItem>
                </Flex>
              </DataListCell>,
              <DataListAction
                key={`action-${actionName}`}
                aria-labelledby={`inline-modifier-${actionName}`}
                id={`action-id-${actionName}`}
                aria-label="Actions"
              >
                {actionName && (
                  <DataListCell key="action-content">
                    <Button variant={ButtonVariant.secondary} onClick={() => onClick(actionName)}>
                      {btnName}
                    </Button>
                  </DataListCell>
                )}
              </DataListAction>
            ]}
          />
        </DataListItemRow>
      </DataListItem>
    );
  };

  return (
    <>
      <PageSection>
        <Content component="p">
          {t(
            'Skupper is a layer 7 network. It enables secure communication across Kubernetes clusters with no VPNs or special firewall rules',
            { skupperName: process.env.SKUPPER_NAME }
          )}
          <br />
          {t('The site console is used during network setup.')}

          <ExternalLink href="https://skupper.io/docs/console/index.html" text={t('Learn more about the console')} />
        </Content>
      </PageSection>

      <DataList aria-label="get-started-data list">
        <DetailItem
          title="Generating tokens"
          description="A grant is required to create a link. The token contains a URL, which locates the link Access of the target site, and a secret, which represents the authority to create a link"
          btnName="Generate a token"
          actionName={Actions.Token}
          onClick={handleOperation}
        />
        <DetailItem
          title="Linking to remote sites"
          description="A link is a site-to-site communication channel. Links serve as a transport for application traffic such as connections and requests. Links are always encrypted using mutual TLS"
          btnName="Create a link"
          actionName={Actions.Link}
          onClick={handleOperation}
        />
        <DetailItem
          title="Expose a service for accepting connections"
          description="Listeners use a routing key to forward connection data to remote connectors"
          btnName="Create a listener"
          actionName={Actions.Listener}
          onClick={handleOperation}
        />
        <DetailItem
          title="Binds local servers to listeners in remote sites"
          description="Connectors are linked to listeners by a matching routing key"
          btnName="Create a connector"
          actionName={Actions.Connector}
          onClick={handleOperation}
        />
      </DataList>

      <PageSection>
        <DeploymentNetworkConsoleButton />
      </PageSection>

      <PageSection>
        <br />
        <Content component="h1">{t('More information on using the CLI')}</Content>
        <br />
        <ExternalLink
          href="https://skupper.io/docs/cli/index.html#creating-using-cli"
          text={t('Creating a site using the CLI')}
        />
        <br />
        <ExternalLink href="https://skupper.io/docs/cli/index.html#linking-sites" text="Linking sites" />
        <br />
        <ExternalLink
          href="https://skupper.io/docs/cli/index.html#exposing-services-ns"
          text={t('Exposing services from a different namespace to the service network')}
        />
        <br />
        <ExternalLink
          href="https://skupper.io/docs/cli/index.html#exposing-services-local"
          text={t('Exposing services on the service network from a local machine')}
        />
      </PageSection>

      <Modal
        hasNoBodyWrapper
        variant={ModalVariant.large}
        isOpen={isModalOpen}
        aria-label={`Form ${action}`}
        showClose={false}
      >
        {ActionFormMap[action]}
      </Modal>
    </>
  );
};

export default GetStarted;
